import React from 'react';
import { View, StyleSheet, Alert } from 'react-native';
import MapView, { Marker } from 'react-native-maps';

const lieux = [
  { id: 1, nom: 'Yaoundé', latitude: 3.8480, longitude: 11.5021 },
  { id: 2, nom: 'Douala', latitude: 4.0511, longitude: 9.7679 },
  { id: 3, nom: 'Garoua', latitude: 9.3015, longitude: 13.3977 },
  { id: 4, nom: 'Bamenda', latitude: 5.9340, longitude: 10.1684 },
];

const MultiMarkerMap = () => {
  const handleMarkerPress = (nom) => {
    Alert.alert('Lieu sélectionné', `Vous avez choisi ${nom}`);
  };

  return (
    <View style={styles.container}>
      <MapView
        style={styles.map}
        initialRegion={{
          latitude: lieux[0].latitude,
          longitude: lieux[0].longitude,
          latitudeDelta: 5,
          longitudeDelta: 5,
        }}
      >
        {lieux.map((lieu) => (
          <Marker
            key={lieu.id}
            coordinate={{
              latitude: lieu.latitude,
              longitude: lieu.longitude,
            }}
            title={lieu.nom}
            onPress={() => handleMarkerPress(lieu.nom)}
          />
        ))}
      </MapView>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1 },
  map: { width: '100%', height: '100%' },
});

export default MultiMarkerMap;
